package com.enterprise.auth.service;

import com.enterprise.auth.model.User;
import com.enterprise.auth.model.BackupCode;
import com.enterprise.auth.repository.BackupCodeRepository;
import com.enterprise.auth.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

@Service
@Transactional
public class BackupCodeService {

    private static final int BACKUP_CODE_LENGTH = 16;
    private static final int NUMBER_OF_CODES = 10;
    private static final String CODE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ23456789";

    @Autowired
    private BackupCodeRepository backupCodeRepository;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private PasswordEncoder passwordEncoder;

    public List<String> generateBackupCodes(Long userId) {
        List<BackupCode> existingCodes = backupCodeRepository.findByUserId(userId);
        if (!existingCodes.isEmpty()) {
            backupCodeRepository.deleteAll(existingCodes);
        }

        List<String> codes = new ArrayList<>();
        SecureRandom random = new SecureRandom();

        for (int i = 0; i < NUMBER_OF_CODES; i++) {
            StringBuilder code = new StringBuilder();
            for (int j = 0; j < BACKUP_CODE_LENGTH; j++) {
                int index = random.nextInt(CODE_CHARS.length());
                code.append(CODE_CHARS.charAt(index));
            }
            codes.add(code.toString());
        }

        List<BackupCode> backupCodes = codes.stream()
                .map(code -> {
                    BackupCode backupCode = new BackupCode();
                    backupCode.setUserId(userId);
                    backupCode.setCode(passwordEncoder.encode(code));
                    backupCode.setUsed(false);
                    backupCode.setCreatedAt(LocalDateTime.now());
                    return backupCode;
                })
                .collect(Collectors.toList());

        backupCodeRepository.saveAll(backupCodes);
        return codes;
    }

    public boolean validateBackupCode(Long userId, String code) {
        BackupCode backupCode = backupCodeRepository.findByUserIdAndCode(userId, passwordEncoder.encode(code));
        if (backupCode != null && !backupCode.isUsed()) {
            backupCode.setUsed(true);
            backupCode.setUsedAt(LocalDateTime.now());
            backupCodeRepository.save(backupCode);
            return true;
        }
        return false;
    }

    public boolean isBackupCodeUsed(Long userId, String code) {
        BackupCode backupCode = backupCodeRepository.findByUserIdAndCode(userId, passwordEncoder.encode(code));
        return backupCode != null && backupCode.isUsed();
    }

    public List<BackupCode> getActiveBackupCodes(Long userId) {
        return backupCodeRepository.findByUserIdAndUsedFalse(userId);
    }

    public void invalidateAllBackupCodes(Long userId) {
        List<BackupCode> codes = backupCodeRepository.findByUserId(userId);
        codes.forEach(code -> code.setUsed(true));
        backupCodeRepository.saveAll(codes);
    }
}